import React from "react"
import Layout from "../components/Layout"
import dealsData from "../../data/deals.json"

const DealDetailPage = ({ pageContext }) => {
  const deal = dealsData.deals.find(d => d.id === pageContext.id)

  if (!deal) {
    return (
      <Layout>
        <h1 style={{ color: "#e0e0e0" }}>Deal not found</h1>
        <a href="/deals/" style={{ color: "#3b82f6" }}>← All deals</a>
      </Layout>
    )
  }

  const categoryIcons = {
    vps: "🖥️", gpu: "🎮", domain: "🌐", storage: "💾", serverless: "⚡", "ai-api": "🧠"
  }

  return (
    <Layout>
      <a href="/deals/" style={{ color: "#666", textDecoration: "none", fontSize: "0.85rem" }}>← All Deals</a>
      
      <div style={{ margin: "2rem 0" }}>
        <span style={{ fontSize: "2rem" }}>{categoryIcons[deal.category] || "📦"}</span>
        <div style={{ fontSize: "0.8rem", color: "#666", marginTop: "0.5rem" }}>{deal.provider}</div>
        <h1 style={{ color: "#e0e0e0", fontSize: "1.8rem", margin: "0.3rem 0" }}>{deal.name}</h1>
        
        <div style={{
          display: "inline-block", padding: "0.3rem 0.8rem", borderRadius: 8, marginTop: "0.5rem",
          background: deal.uncertain ? "#7c2d12" : "#14532d", color: deal.uncertain ? "#fb923c" : "#4ade80",
          fontSize: "0.8rem", fontWeight: 600,
        }}>
          {deal.uncertain ? "⚠ Verify price" : "✅ Price verified"} · {deal.lastVerified}
        </div>
      </div>

      {/* Price */}
      <div style={{ background: "#111", border: "1px solid #222", borderRadius: 12, padding: "1.5rem", margin: "1.5rem 0" }}>
        <h2 style={{ color: "#e0e0e0", fontSize: "1.1rem", marginBottom: "1rem" }}>Pricing</h2>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(120px, 1fr))", gap: "1rem" }}>
          {deal.price.monthly && <div><div style={{ color: "#10b981", fontSize: "2rem", fontWeight: 800 }}>${deal.price.monthly}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>monthly</div></div>}
          {deal.price.hourly && <div><div style={{ color: "#10b981", fontSize: "2rem", fontWeight: 800 }}>${deal.price.hourly}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>per hour</div></div>}
          {deal.price.annual && <div><div style={{ color: "#10b981", fontSize: "2rem", fontWeight: 800 }}>${deal.price.annual}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>per year</div></div>}
          {deal.price.annualPrice && <div><div style={{ color: "#10b981", fontSize: "2rem", fontWeight: 800 }}>${deal.price.annualPrice}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>per year</div></div>}
          {deal.price.monthlyPerGB && <div><div style={{ color: "#10b981", fontSize: "2rem", fontWeight: 800 }}>${deal.price.monthlyPerGB}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>per GB/mo</div></div>}
          {deal.price.inputPer1M && <div><div style={{ color: "#10b981", fontSize: "2rem", fontWeight: 800 }}>${deal.price.inputPer1M}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>input/1M tokens</div></div>}
          {deal.price.outputPer1M && <div><div style={{ color: "#f59e0b", fontSize: "1.2rem", fontWeight: 700 }}>${deal.price.outputPer1M}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>output/1M tokens</div></div>}
          {deal.price.setup > 0 && <div><div style={{ color: "#f59e0b", fontSize: "1.2rem", fontWeight: 700 }}>${deal.price.setup}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>setup fee</div></div>}
          <div><div style={{ color: "#888", fontSize: "1rem" }}>{deal.price.currency}</div><div style={{ color: "#666", fontSize: "0.8rem" }}>currency</div></div>
        </div>
      </div>

      {/* Specs */}
      {Object.keys(deal.specs).length > 0 && (
        <div style={{ background: "#111", border: "1px solid #222", borderRadius: 12, padding: "1.5rem", margin: "1.5rem 0" }}>
          <h2 style={{ color: "#e0e0e0", fontSize: "1.1rem", marginBottom: "1rem" }}>Specifications</h2>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(150px, 1fr))", gap: "0.8rem" }}>
            {Object.entries(deal.specs).map(([k, v]) => (
              <div key={k} style={{ padding: "0.5rem", background: "#0a0a0a", borderRadius: 8 }}>
                <div style={{ color: "#555", fontSize: "0.7rem", textTransform: "uppercase" }}>{k}</div>
                <div style={{ color: "#ccc", fontSize: "0.9rem" }}>{v}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Features */}
      {deal.features && deal.features.length > 0 && (
        <div style={{ background: "#111", border: "1px solid #222", borderRadius: 12, padding: "1.5rem", margin: "1.5rem 0" }}>
          <h2 style={{ color: "#e0e0e0", fontSize: "1.1rem", marginBottom: "1rem" }}>Features</h2>
          <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
            {deal.features.map((f, i) => (
              <li key={i} style={{ color: "#aaa", padding: "0.3rem 0", fontSize: "0.9rem" }}>✓ {f}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Tags */}
      {deal.tags && (
        <div style={{ display: "flex", gap: "0.4rem", flexWrap: "wrap", margin: "1rem 0" }}>
          {deal.tags.map((t, i) => (
            <span key={i} style={{ fontSize: "0.7rem", padding: "0.2rem 0.5rem", borderRadius: 4, background: "#1a1a1a", color: "#666" }}>
              {t}
            </span>
          ))}
        </div>
      )}

      {/* CTA */}
      <a href={deal.url} target="_blank" rel="noopener noreferrer" style={{
        display: "inline-block", padding: "0.8rem 2rem", borderRadius: 8,
        background: "#10b981", color: "#000", fontWeight: 700, textDecoration: "none",
        fontSize: "0.9rem", marginTop: "1rem",
      }}>
        Visit {deal.provider} →
      </a>
    </Layout>
  )
}

export const Head = ({ pageContext }) => {
  const deal = dealsData.deals.find(d => d.id === pageContext?.id)
  return (
    <>
      <title>{deal ? `${deal.provider} ${deal.name} — DevBundles` : "Deal — DevBundles"}</title>
    </>
  )
}

export default DealDetailPage
